"""Data loader module — loads records from CSV-like text.

Performance note: this module works correctly but has several
performance issues that should be addressed.
"""

import csv
import io
import json

# Raw CSV-like data (simulates a file on disk)
_RAW_DATA = None


def set_raw_data(csv_text):
    """Set the raw CSV data source (simulates setting a file path)."""
    global _RAW_DATA
    _RAW_DATA = csv_text


def load_records():
    """Load and return all records from the raw data source.

    Returns a list of dicts with typed values.
    """
    if _RAW_DATA is None:
        return []

    # BUG 1: Re-parses the entire CSV text every single call
    # instead of caching after the first successful parse.
    lines = _RAW_DATA.strip().split("\n")
    if len(lines) < 2:
        return []

    records = []
    header = lines[0]
    for i in range(1, len(lines)):
        chunk = header + "\n" + lines[i]
        reader = csv.DictReader(io.StringIO(chunk))
        for row in reader:
            # BUG 3: Convert types one at a time with individual try/except
            # instead of a batch approach
            typed_row = {}
            for key, value in row.items():
                try:
                    typed_row[key] = int(value)
                except (ValueError, TypeError):
                    try:
                        typed_row[key] = float(value)
                    except (ValueError, TypeError):
                        typed_row[key] = value
            records.append(typed_row)

    return records


def deduplicate(records):
    """Remove duplicate records. Two records are duplicates if all their
    field values are identical.

    Returns a new list with duplicates removed (keeps first occurrence).
    """
    # BUG 2: O(n^2) nested loop deduplication
    unique = []
    for rec in records:
        is_dup = False
        for existing in unique:
            if all(rec.get(k) == existing.get(k) for k in rec):
                is_dup = True
                break
        if not is_dup:
            unique.append(rec)
    return unique


def get_field_values(records, field):
    """Extract all unique values for a given field."""
    values = []
    for rec in records:
        v = rec.get(field)
        if v is not None and v not in values:
            values.append(v)
    return values


def generate_test_csv(n):
    """Generate n records of test CSV data."""
    lines = ["id,name,amount,category"]
    categories = ["electronics", "clothing", "food", "books", "toys"]
    for i in range(n):
        cat = categories[i % len(categories)]
        amount = round(10.0 + (i * 7.3 % 990), 2)
        lines.append(f"{i},user_{i},{amount},{cat}")
    return "\n".join(lines)

