"""Search index module — builds an index over records for fast lookup.

Performance note: this module works correctly but has several
performance issues that should be addressed.
"""


class SearchIndex:
    """A searchable index over record dicts."""

    def __init__(self, index_field):
        """Create an index on the given field.

        Args:
            index_field: The record field to index on.
        """
        self.index_field = index_field
        self._records = []  # BUG: stores as flat list, no actual index structure

    def add_record(self, record):
        """Add a record to the index."""
        self._records.append(record)
        # BUG 2: Rebuild entire index from scratch on each insert.
        # (The 'index' here is just re-sorting the list each time,
        #  which is O(n log n) per insert instead of O(1) amortized.)
        self._records.sort(key=lambda r: str(r.get(self.index_field, "")))

    def add_many(self, records):
        """Add multiple records to the index."""
        for rec in records:
            self.add_record(rec)

    def lookup(self, value):
        """Find all records where index_field == value.

        Returns a list of matching records.
        """
        # BUG 1: Linear scan instead of dict-based O(1) lookup
        results = []
        for rec in self._records:
            if rec.get(self.index_field) == value:
                results.append(rec)
        return results

    def lookup_range(self, min_val, max_val):
        """Find all records where min_val <= index_field value <= max_val.

        Only works for numeric fields. Returns list of matching records.
        """
        # Linear scan for range queries
        results = []
        for rec in self._records:
            val = rec.get(self.index_field)
            if val is not None and min_val <= val <= max_val:
                results.append(rec)
        return results

    def count(self):
        """Return total number of indexed records."""
        return len(self._records)

    def unique_values(self):
        """Return sorted list of unique values for the indexed field."""
        seen = []
        for rec in self._records:
            val = rec.get(self.index_field)
            if val is not None and val not in seen:
                seen.append(val)
        return sorted(seen)

    def remove(self, value):
        """Remove all records with the given index field value.

        Returns the number of records removed.
        """
        original_len = len(self._records)
        self._records = [r for r in self._records if r.get(self.index_field) != value]
        return original_len - len(self._records)
